// fibGen streams the first n Fibonacci numbers on a channel, closing it at the end.
func fibGen(n int) <-chan int {
	out := make(chan int)
	go func() {
		defer close(out) // lets the consumer's range terminate
		a, b := 0, 1
		for i := 0; i < n; i++ {
			out <- a
			a, b = b, a+b
		}
	}()
	return out
}

