// MaxOf returns the largest of first and rest. Requiring at least `first`
// guarantees there is always a value to return (no empty-input ambiguity).
func MaxOf[T cmp.Ordered](first T, rest ...T) T {
	best := first
	for _, v := range rest {
		if v > best {
			best = v
		}
	}
	return best
}

