// fetch now selects on ctx.Done so a caller can cancel or time it out.
func fetch(ctx context.Context, d time.Duration) (string, error) {
	select {
	case <-time.After(d):
		return "ok", nil
	case <-ctx.Done():
		return "", ctx.Err()
	}
}

func main() {
