import (
	"fmt"
	"sync"
	"sync/atomic"
)

func main() {
	var slot atomic.Int32
	winners := make(chan int, 10)

	var wg sync.WaitGroup
	for i := 0; i < 10; i++ {
		wg.Add(1)
		go func(id int) {
			defer wg.Done()
			// Only the first goroutine to swap 0->1 succeeds; the rest see 1.
			if slot.CompareAndSwap(0, 1) {
				winners <- id
			}
		}(i)
	}
	wg.Wait()
	close(winners)

	count := 0
	for range winners {
		count++
	}
	fmt.Println("winners:", count) // exactly 1
}
```

