// digitalRoot repeatedly sums the decimal digits of n until one digit remains.
func digitalRoot(n int) int {
	if n < 10 {
		return n
	}
	sum := 0
	for n > 0 {
		sum += n % 10
		n /= 10
	}
	return digitalRoot(sum)
}

func main() {
	// 9+8+7+5 = 29 -> 2+9 = 11 -> 1+1 = 2
	fmt.Println(digitalRoot(9875)) // 2
}
